// Stub for JIT-generated chlkc_descriptors.h (clang-tidy analysis only)
//
// The real chlkc_descriptors.h is generated by tt_metal/jit_build/genfiles.cpp
// and contains pack/unpack data format arrays, tile dimension arrays, and
// math scalar descriptors.  All of that content is already provided by the
// force-included kernel_clang_tidy_prelude.h, so this stub is intentionally
// empty beyond the pragma once guard.
//
// The generated file also conditionally includes llk_defs.h under
// UCK_CHLKC_MATH; that header is available in the llk_lib include path
// and is included via the normal LLK headers, so no stub is needed for it.

#pragma once
